class Solution:
    def getLucky(self, s, k):
        total = 0
        for ch in s:
            val = ord(ch) - 96
            total += val // 10 + val % 10
        for _ in range(k - 1):
            nxt = 0
            while total:
                nxt += total % 10
                total //= 10
            total = nxt
        return total

