var getLucky = function(s, k) {
    let total = 0;
    for (const ch of s) {
        const val = ch.charCodeAt(0) - 96;
        total += Math.floor(val / 10) + (val % 10);
    }
    for (let r = 0; r < k - 1; r++) {
        let nxt = 0;
        while (total > 0) {
            nxt += total % 10;
            total = Math.floor(total / 10);
        }
        total = nxt;
    }
    return total;
};
